<?phpclass CuestionarioController extends Controller_Abstract{    public function init()    {        /* Initialize action controller here */		//Agrego las operaciones del init de Controller/Abstract y agrego el layout-admin		parent::init();		$this->_helper->_layout->setLayout('layout-cuestionario');    }		/*	*	COMENZAR EL CUESTIONARIO	*	*	VERIFICA QUE EL USUARIO NO TENGO UN CUESTIONARIO YA COMENZADO	*	SI LO TIENE, LO MANDA AL INDICADOR QUE LE SIGUE A SU ┌LTIMA RESPUESTA	*	*/		public function comenzarAction()	{		$redirect = '/cuestionario/responder';		//Comprobar estatus de los cuestioinario del Usuario		$correo = Zend_Auth::getInstance()->getIdentity();		$usuario = Model_Usuario::getInstance()->getUsuario($correo);		$idUsuario = $usuario['id_usuario'];		//Si el usuario no tiene ning˙n cuestionario comenzado, generar uno nuevo		if( false == Model_Cuestionario::getInstance()->getCuestionarioComenzadoByUsuario($idUsuario) )		{			$this->view->sidebar1 = Model_Informacion::getInstance()->getInformacion('sidebarCuestionario1');			$this->view->contenido1 = Model_Informacion::getInstance()->getInformacion('contenidoCuestionario1');									//Identidad del usuario			$this->view->perfil = $usuario;						$encuesta = Model_Encuesta::getInstance()->getEncuestaActiva();						if($this->getRequest()->getPost('botonComenzarCuestionario'))			{					$cabeza = Model_Indicador::getInstance()->getCabeza();					$cola = Model_Indicador::getInstance()->getCola(); //Indica una cola determinada, en caso de errores del editor							//Nuevo cuestionario = (usuario,estatus,encuesta,cabeza,cola,ultimo)					$idCuestionario = Model_Cuestionario::getInstance()->nuevoCuestionario(													$idUsuario,													'comenzado',													$encuesta['id_encuesta'],													$cabeza['id_indicador'],													$cola['id_indicador']);										$this->_helper->redirector->gotoUrlAndExit($redirect);			}		}		else		{			$this->_helper->redirector->gotoUrlAndExit($redirect);		}			}		/*	*	RESPONDER EL CUESTIONARIO	*	*	VERIFICA CU┴L ES LA ┌LTIMA PREGUNTA RESPONDIDA POR EL USUARIO	*	Y LO REDIRIGE A LA PREGUNTA SIGUIENTE	*	*/	    public function responderAction()    {	        //Acciones		$correo = Zend_Auth::getInstance()->getIdentity();		$usuario = Model_Usuario::getInstance()->getUsuario($correo);		$this->view->perfil =$usuario;				$encuesta = Model_Encuesta::getInstance()->getEncuestaActiva();				$idUsuario = $usuario['id_usuario'];		if( false == Model_Cuestionario::getInstance()->getCuestionarioComenzadoByUsuario($idUsuario) )		{			$redirect = '/../cuestionario/comenzar';			$this->_helper->redirector->gotoUrlAndExit($redirect);		}		$redirect = '/../cuestionario/comenzar';				$idCuestionario = Model_Cuestionario::getInstance()->getCuestionarioComenzadoByUsuario($idUsuario);		$idIndicador = Model_Cuestionario::getInstance()->getUltimoIndicador($idCuestionario);		$indicador = Model_Indicador::getInstance()->getIndicador($idIndicador);		$factor = Model_FactorConversion::getInstance()->getFactorConversion($indicador['tbl_factorConversion_id_factorConversion']);									if($this->getRequest()->getPost('botonSiguiente'))		{			//Recoge el ID de la alternativa seleccionada por el usuario			$idAlternativa = $this->getRequest()->getParam('seleccion_usuario');			$peso = Model_Alternativa::getInstance()->getPesoAlternativa($idAlternativa);						//CALCULA EL RESULTADO DE LA FORMULA			$resultado = doubleval(Model_CuestionarioAlternativa::getInstance()->calcularResultado($peso,$factor['valor_factorConversion'],$indicador['formula_indicador'],$indicador['ficha_indicador'],$idCuestionario));						if($usuario['rol_usuario']=='editor'){			var_dump(doubleval($resultado));}									//INSERTAR RESULTADO			Model_CuestionarioAlternativa::getInstance()->insertRespuesta($idCuestionario,$idAlternativa,doubleval($resultado),$indicador[			'id_indicador']);						$idNextIndicador = Model_Alternativa::getInstance()->getIndicadorSiguiente($idAlternativa);						//Averigua si es la ˙ltima pregunta			if( $idNextIndicador['tbl_indicador_id_indicador_siguiente'] == $indicador['id_indicador'] || $indicador['id_indicador'] == Model_Cuestionario::getInstance()->getCola($idCuestionario))			{				$redirect = '/../cuestionario/terminar';				$this->_helper->redirector->gotoUrlAndExit($redirect);			}			Model_Cuestionario::getInstance()->updateUltimo($idCuestionario,$idNextIndicador['tbl_indicador_id_indicador_siguiente']);			$indicador = Model_Indicador::getInstance()->getIndicador($idNextIndicador['tbl_indicador_id_indicador_siguiente']);		}		$grupo = Model_Indicador::getInstance()->getGrupoByIndicador($indicador['id_indicador']);		$idCola = Model_Cuestionario::getInstance()->getCola($idCuestionario);		$indicadorCola = Model_Indicador::getInstance()->getIndicador($idCola);		$this->view->indicador = $indicador;		$this->view->cola = $indicadorCola['orden_indicador'];		$this->view->alternativas = Model_Alternativa::getInstance()->getAlternativasByIndicador($indicador['id_indicador']);		$this->view->grupo = Model_Grupo::getInstance()->getGrupoById($grupo['tbl_grupo_id_grupo']);			}		/*	*	TERMINAR EL CUESTIONARIO	*	*	CAMBIA EL ESTATUS DEL CUESTIONARIO ACTIVO Y ENV═A AL ENCUESTADO	*	A LA P┴GINA DE RESULTADOS	*	*/		public function terminarAction()	{		//Acciones		$correo = Zend_Auth::getInstance()->getIdentity();		$usuario = Model_Usuario::getInstance()->getUsuario($correo);		$this->view->perfil =$usuario;				$encuesta = Model_Encuesta::getInstance()->getEncuestaActiva();				$idUsuario = $usuario['id_usuario'];		if( false == Model_Cuestionario::getInstance()->getCuestionarioComenzadoByUsuario($idUsuario) )		{			$redirect = '/../cuestionario/comenzar';			$this->_helper->redirector->gotoUrlAndExit($redirect);		}				$idCuestionario = Model_Cuestionario::getInstance()->getCuestionarioComenzadoByUsuario($idUsuario);		Model_Cuestionario::getInstance()->setEstatus($idCuestionario,'terminado');		$redirect = '/../usuario/resultados/cuestionario/' . $idCuestionario;		$this->_helper->redirector->gotoUrlAndExit($redirect);	}}//echo '<pre>ID grupo : ' . $grupo['tbl_grupo_id_grupo'] . ' resultado: ' . $resultado['peso_alternativa'] . '</pre>';